- `shouldSuppressLocalPayloadPrompt?({cfg, accountId, payload, hint?})` → boolean
- `beforeDeliverPayload?({cfg, target, payload, hint?})` → Promise<void> | void
- `resolveTarget?({cfg?, to?, allowFrom?, accountId?, mode?})` → {ok: true, to: string} | {ok: false, error}
- `sendPayload?(ctx: ChannelOutboundPayloadContext)` → Promise<OutboundDeliveryResult>
- `sendFormattedText?(ctx)` → Promise<OutboundDeliveryResult[]>
- `sendFormattedMedia?(ctx)` → Promise<OutboundDeliveryResult>
