  register?: (api: OpenClawPluginApi) => void;
};
```

#### **`defineSetupPluginEntry` (from `core.ts`)**
```typescript
function defineSetupPluginEntry<TPlugin>(plugin: TPlugin) {
  return { plugin };
}
```

---

### 7. **Config Schema Types**

```typescript
// From src/plugins/types.ts
export type OpenClawPluginConfigSchema = {
  safeParse?: (value: unknown) => {
    success: boolean;
    data?: unknown;
    error?: {
      issues?: Array<{ path: Array<string | number>; message: string }>;
    };
  };
  parse?: (value: unknown) => unknown;
  validate?: (value: unknown) => PluginConfigValidation;
  uiHints?: Record<string, PluginConfigUiHint>;
  jsonSchema?: Record<string, unknown>;
};

export type PluginConfigUiHint = {
  label?: string;
  help?: string;
  tags?: string[];
  advanced?: boolean;
  sensitive?: boolean;
  placeholder?: string;
};
```

---

### 8. **Plugin API Surface** (from OpenClawPluginApi)

Plugins use the API passed to `register()` to declare capabilities:

```typescript
api.registerProvider(providerPlugin);
api.registerSpeechProvider(speechProvider);
api.registerMediaUnderstandingProvider(mediaProvider);
api.registerImageGenerationProvider(imageProvider);
api.registerChannel({ plugin: channelPlugin });
api.registerCliBackend(cliBackend);
api.registerCli(registrar, options);
api.registerGatewayMethod(methodId, handler);
api.registerTool(toolFactory, options);
api.registerService(serviceDefinition);
api.registerCommand(commandDefinition);
api.registerHook(hookDefinition, options);
```

---

### 9. **Registration Modes**

Plugins support different registration contexts:

```typescript
// In core.ts defineChannelPluginEntry:
if (api.registrationMode === "cli-metadata") {
  registerCliMetadata?.(api);
  return;  // Setup-only mode
}
// "full" mode continues with full registration
setRuntime?.(api.runtime);
api.registerChannel({ plugin: plugin as ChannelPlugin });
if (api.registrationMode === "full") {
  registerCliMetadata?.(api);
  registerFull?.(api);  // Extra registration for full runtime
}
```

Registration modes:
- **"cli-metadata"**: Setup/discovery only, no runtime overhead
- **"setup-only"**: Extended setup but no full features
- **"full"**: Complete plugin with all runtime features

---

### 10. **Plugin SDK Entrypoints Registry**

From `/scripts/lib/plugin-sdk-entrypoints.json`, OpenClaw exposes 244+ SDK entrypoints including:

Core:
- `index`, `core`, `plugin-entry`, `provider-entry`

Provider & Setup:
- `provider-setup`, `self-hosted-provider-setup`, `channel-setup`, `setup`, `setup-adapter-runtime`

Runtime:
- `plugin-runtime`, `channel-runtime`, `reply-runtime`, `config-runtime`, `approval-runtime`, etc.

Specific Channels:
- `matrix-runtime-heavy`, `matrix-runtime-shared`, `discord`, `slack`, `telegram`, `signal`, `whatsapp`, `zalo`, etc.

Providers:
- `amazon-bedrock`, `anthropic-vertex`, `deepseek`, `openai`, `mistral`, `groq`, `together`, `ollama`, etc.

---

### 11. **Test Patterns**

Test files verify plugin registration behavior:

```typescript
// /extensions/matrix/index.test.ts
describe("matrix plugin", () => {
  it("registers matrix CLI through a descriptor-backed lazy registrar", async () => {
    const api = createTestPluginApi({
      id: "matrix",
      registrationMode: "cli-metadata",
      registerCli: vi.fn(),
      registerGatewayMethod: vi.fn(),
    });

    matrixPlugin.register(api);

    expect(registerCli).toHaveBeenCalledWith(expect.any(Function), {
      descriptors: [...]
    });
  });

  it("keeps runtime bootstrap out of setup-only registration", () => {
    const api = createTestPluginApi({
      registrationMode: "setup-only",
    });
    matrixPlugin.register(api);
    expect(registerGatewayMethod).not.toHaveBeenCalled();
  });
});
```

---

### 12. **Key Patterns & Best Practices**

1. **Manifest-First Design**: `openclaw.plugin.json` must be valid before plugin code executes
2. **Separation of Concerns**:
   - Manifest: discovery, config validation, auth metadata
   - package.json: npm metadata, entrypoints, install config
   - index.ts: plugin registration logic
   - setup-entry.ts: setup-only plugins

3. **Config Schema Flexibility**: Plugins can use Zod-like `parse()`, `safeParse()`, or custom `validate()` methods

4. **Lazy Registration**: Plugins use lazy imports for heavy modules only needed in full mode

5. **Channel Plugins**: Use `defineChannelPluginEntry` + `setRuntime()` callback for proper runtime wiring

6. **Provider Plugins**: Use `defineSingleProviderPluginEntry` for standard auth flows or `definePluginEntry` for complex registration

---

### **File Locations**

- **Plugin Manifests**: `/extensions/{plugin-id}/openclaw.plugin.json`
- **Entry Points**: `/extensions/{plugin-id}/index.ts`, `/extensions/{plugin-id}/setup-entry.ts`
- **Entry Type Definitions**: `/src/plugin-sdk/plugin-entry.ts`, `/src/plugin-sdk/core.ts`, `/src/plugin-sdk/provider-entry.ts`
- **Plugin Type System**: `/src/plugins/types.ts`
- **SDK Registry**: `/scripts/lib/plugin-sdk-entrypoints.json`
- **Manifest Documentation**: `/docs/plugins/manifest.md`
- **SDK Documentation**: `/docs/plugins/sdk-*.md`

