91	function runTlonCommand(binary: string, args: string[]): Promise<string> {
92	  return new Promise((resolve, reject) => {
93	    const child = spawn(binary, args, { env: process.env });
94	
95	    let stdout = "";
96	    let stderr = "";
97	
98	    child.stdout.on("data", (data) => {
99	      stdout += data.toString();
100	    });
101	
102	    child.stderr.on("data", (data) => {
103	      stderr += data.toString();
104	    });
105	
106	    child.on("error", (err) => {
107	      reject(new Error(`Failed to run tlon: ${err.message}`));
108	    });
109	
110	    child.on("close", (code) => {
111	      if (code !== 0) {
112	        reject(new Error(stderr || `tlon exited with code ${code}`));
113	        return;
114	      }
115	      resolve(stdout);
116	    });
117	  });
118	}
