#### File 3: `extensions/pulseboard/src/types.ts`

**Purpose**: Define the account config, resolved account, and message interfaces.

**Pattern source**: Follows Tlon's `types.ts` structure -- a config type, a resolved account type, a `resolveAccount` function, and a `listAccountIds` function. Also adds `PulseBoardMessage` as specified in the requirements.

**Key decisions**:
- `PulseBoardConfig`: minimal fields -- `enabled`, `name`, `apiKey` (as a string; could use `SecretInput` from `openclaw/plugin-sdk/secret-input` for production), `endpoint`, `dmPolicy`, `allowFrom`
- `PulseBoardAccount` (the resolved type): `accountId`, `name`, `enabled`, `configured`, `apiKey`, `endpoint`, standard config reference
- `PulseBoardMessage`: `id`, `from`, `to`, `text`, `timestamp`
- `resolvePulseBoardAccount`: resolves from `cfg.channels.pulseboard` following the top-level pattern (simpler than scoped multi-account for a stub)
- `listPulseBoardAccountIds`: returns account IDs from config

**Import sources**:
- `DEFAULT_ACCOUNT_ID`, `normalizeAccountId` from `openclaw/plugin-sdk/account-id`
- `listCombinedAccountIds` from `openclaw/plugin-sdk/account-resolution`
- `OpenClawConfig` from `openclaw/plugin-sdk/core`

**Contents**:
```typescript
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { listCombinedAccountIds } from "openclaw/plugin-sdk/account-resolution";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";

export interface PulseBoardConfig {
  enabled?: boolean;
  name?: string;
  apiKey?: string;
  endpoint?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

export interface PulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiKey: string;
  endpoint: string;
  config: PulseBoardConfig;
}

export interface PulseBoardMessage {
  id: string;
  from: string;
  to: string;
  text: string;
  timestamp: number;
}

function resolvePulseBoardChannelConfig(cfg: OpenClawConfig): PulseBoardConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardConfig
    | undefined;
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): PulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? DEFAULT_ACCOUNT_ID);
  const pbCfg = resolvePulseBoardChannelConfig(opts.cfg);

  const apiKey = pbCfg?.apiKey?.trim() ?? "";
  const endpoint = pbCfg?.endpoint?.trim() ?? "";
  const configured = Boolean(apiKey && endpoint);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    apiKey,
    endpoint,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      endpoint: pbCfg?.endpoint,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}

export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = resolvePulseBoardChannelConfig(cfg);
  if (!pbCfg) {
    return [];
  }
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: pbCfg.apiKey?.trim() ? DEFAULT_ACCOUNT_ID : undefined,
  });
}

export function resolveDefaultPulseBoardAccountId(_cfg: OpenClawConfig): string {
  return DEFAULT_ACCOUNT_ID;
}
```

