**Purpose**: Runtime store using the SDK's `createPluginRuntimeStore`.

**Pattern source**: Follows the Tlon pattern exactly -- importing `PluginRuntime` from `openclaw/plugin-sdk/runtime-store` (which re-exports it from the plugins runtime types). This avoids needing a dedicated `api.ts` or `runtime-api.ts` barrel, since PulseBoard has no dedicated SDK facade at `openclaw/plugin-sdk/pulseboard`.

**Contents**:
```typescript
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";
import type { PluginRuntime } from "openclaw/plugin-sdk/runtime-store";

const { setRuntime: setPulseBoardRuntime, getRuntime: getPulseBoardRuntime } =
  createPluginRuntimeStore<PluginRuntime>("PulseBoard runtime not initialized");
export { getPulseBoardRuntime, setPulseBoardRuntime };
```

**Note**: The Tlon extension imports `PluginRuntime` from `openclaw/plugin-sdk/plugin-runtime`. Either source works since both re-export the same type from `src/plugins/runtime/types.js`. Using `openclaw/plugin-sdk/runtime-store` is slightly more self-contained (one import path for both the type and the factory).

#### File 5: `extensions/pulseboard/src/channel.ts`

**Purpose**: The full channel plugin definition using `createChatChannelPlugin`.

**Pattern source**: Composite of Nostr (for inline meta, DM-only capabilities, simple outbound) and Tlon (for import paths, inline meta, no dedicated SDK facade).

**Key decisions**:
- **Meta**: Inline object, NOT `getChatChannelMeta`. Fields match what's in `package.json`'s `openclaw.channel` block.
- **Capabilities**: `chatTypes: ["direct"]`, `media: false` (stub DM-only).
- **Config adapter**: Uses `createTopLevelChannelConfigAdapter` from `openclaw/plugin-sdk/channel-config-helpers` (same approach as Nostr).
- **Setup adapter**: A simple stub adapter that validates `apiKey` and `endpoint` presence.
- **Status**: Uses `createComputedAccountStatusAdapter` from `openclaw/plugin-sdk/status-helpers`.
- **Messaging**: Simple `normalizeTarget` and `targetResolver`.
- **Gateway**: Stub `startAccount` that logs startup and returns a no-op stop function.
- **Outbound**: Stub `sendText` that returns an `attachChannelToResult` result with a generated message ID.
- **Security**: Uses `createScopedDmSecurityResolver` from `openclaw/plugin-sdk/channel-config-helpers`.
- **Pairing**: Simple text pairing with stub notification.

**Type annotation**: Uses `as ChannelPlugin` cast on the export (like IRC does) since the generic `PulseBoardAccount` type may not exactly match the plugin's expected shape without the cast.

**Contents**:
```typescript
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import {
  createTopLevelChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import {
  resolvePulseBoardAccount,
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  type PulseBoardAccount,
} from "./types.js";

const PULSEBOARD_CHANNEL_ID = "pulseboard" as const;

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<PulseBoardAccount>({
  sectionKey: PULSEBOARD_CHANNEL_ID,
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "apiKey", "endpoint", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom.map((entry) => String(entry).trim()).filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<PulseBoardAccount>({
  channelKey: PULSEBOARD_CHANNEL_ID,
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
});

const pulseBoardSetupAdapter = {
  resolveAccountId: ({ accountId }: { accountId?: string | null }) =>
    accountId ?? DEFAULT_ACCOUNT_ID,
  applyAccountConfig: ({ cfg }: { cfg: unknown }) => cfg,
  validateInput: () => null,
};

export const pulseBoardPlugin: ChannelPlugin<PulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: PULSEBOARD_CHANNEL_ID,
    meta: {
      id: PULSEBOARD_CHANNEL_ID,
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time dashboard messaging via PulseBoard",
      order: 110,
    },
    capabilities: {
      chatTypes: ["direct"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    setup: pulseBoardSetupAdapter,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            endpoint: account.endpoint,
          },
        }),
    },
    messaging: {
      normalizeTarget: (target) => target.trim().toLowerCase(),
      targetResolver: {
        looksLikeId: (input) => /^[a-z0-9._-]+$/i.test(input.trim()),
        hint: "<pulseboard-user-id>",
      },
    },
    status: {
      ...createComputedAccountStatusAdapter<PulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) =>
          accounts.flatMap((account) => {
            if (!account.configured) {
              return [
                {
                  channel: PULSEBOARD_CHANNEL_ID,
                  accountId: account.accountId,
                  kind: "config" as const,
                  message: "PulseBoard not configured (missing apiKey or endpoint)",
                },
              ];
            }
            return [];
          }),
        buildChannelSummary: ({ snapshot }) => ({
          configured: (snapshot as { configured?: boolean }).configured ?? false,
          endpoint: (snapshot as { endpoint?: string }).endpoint ?? null,
        }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            endpoint: account.endpoint,
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (endpoint: ${account.endpoint})`,
        );

        if (!account.configured) {
          throw new Error("PulseBoard not configured (missing apiKey or endpoint)");
        }

        ctx.setStatus({
          accountId: account.accountId,
          endpoint: account.endpoint,
        });

        ctx.log?.info(`[${account.accountId}] PulseBoard provider started`);

        return {
          stop: () => {
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: "Your PulseBoard pairing request has been approved!",
      notify: async () => {
        // Stub: no real notification delivery yet
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      // Stub: no real PulseBoard API call
      return attachChannelToResult(PULSEBOARD_CHANNEL_ID, {
        to,
        messageId: `pulseboard-${Date.now()}`,
      });
    },
  },
});
```

