54	  let inDouble = false;
55	  let inSingle = false;
56	  let escape = false;
57	
58	  for (const ch of str) {
59	    if (escape) {
60	      cur += ch;
61	      escape = false;
62	      continue;
63	    }
64	    if (ch === "\\" && !inSingle) {
65	      escape = true;
66	      continue;
67	    }
68	    if (ch === '"' && !inSingle) {
69	      inDouble = !inDouble;
70	      continue;
71	    }
72	    if (ch === "'" && !inDouble) {
73	      inSingle = !inSingle;
74	      continue;
75	    }
