import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
} from "openclaw/plugin-sdk/account-id";
import { listCombinedAccountIds } from "openclaw/plugin-sdk/account-resolution";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";

export interface PulseBoardAccount {
  boardUrl: string;
  apiToken: string;
  username: string;
}

export interface PulseBoardConfig {
  accounts: Record<string, PulseBoardAccount>;
}

export interface PulseBoardMessage {
  id: string;
  boardId: string;
  authorId: string;
  content: string;
  timestamp: number;
}

/**
 * Resolved account ready for runtime use.
 */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  boardUrl: string;
  apiToken: string;
  username: string;
  config: PulseBoardAccountConfig;
}

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  boardUrl?: string;
  apiToken?: string;
  username?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

function resolvePulseBoardChannelConfig(
  cfg: OpenClawConfig,
): PulseBoardAccountConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | PulseBoardAccountConfig
    | undefined;
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(opts.accountId ?? DEFAULT_ACCOUNT_ID);
  const pbCfg = resolvePulseBoardChannelConfig(opts.cfg);

  const boardUrl = pbCfg?.boardUrl?.trim() ?? "";
  const apiToken = pbCfg?.apiToken?.trim() ?? "";
  const username = pbCfg?.username?.trim() ?? "";
  const configured = Boolean(boardUrl && apiToken && username);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    boardUrl,
    apiToken,
    username,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      boardUrl: pbCfg?.boardUrl,
      apiToken: pbCfg?.apiToken,
      username: pbCfg?.username,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}

export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = resolvePulseBoardChannelConfig(cfg);
  if (!pbCfg) {
    return [];
  }
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: pbCfg.boardUrl?.trim() ? DEFAULT_ACCOUNT_ID : undefined,
  });
}

export function resolveDefaultPulseBoardAccountId(_cfg: OpenClawConfig): string {
  return DEFAULT_ACCOUNT_ID;
}

